def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        usage_ratio = item / capacity
        base_score = 0
        if usage_ratio > 1.5:
            base_score = 2000 + 25 * (usage_ratio - 1.5)**3
        elif usage_ratio > 1:
            base_score = 1200 + 15 * (usage_ratio - 1)**2
        else:
            if usage_ratio > 0.9:
                base_score += 60 * (usage_ratio ** 1.5)
            elif usage_ratio > 0.7:
                base_score += 40 * (usage_ratio ** 1.2)
            elif usage_ratio > 0.4:
                base_score += 20 * usage_ratio
            else:
                base_score += 5 * usage_ratio
            if capacity < 5:
                base_score += 12
            elif 5 <= capacity <= 20:
                base_score += 7
            elif capacity > 150:
                base_score -= 8
            if i % 3 == 0:
                base_score *= 1.15
            elif i % 3 == 1:
                base_score *= 0.85
            else:
                base_score *= 1.05
        extra_penalty = 0
        for j in range(len(bins)):
            if i == j:
                continue
            dist = abs(i - j)
            if bins[j] < item and dist < 3:
                extra_penalty += 3 / dist
        priorities[i] = base_score + extra_penalty
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) > 0:
        min_val = np.min(finite_priorities)
        for k in range(len(priorities)):
            if not np.isfinite(priorities[k]):
                priorities[k] = min_val + 150
    else:
        priorities.fill(1000)
    for idx in range(len(priorities)):
        if priorities[idx] > 1500:
            priorities[idx] *= 1.2
        elif priorities[idx] < 20:
            priorities[idx] *= 0.8
        if idx % 5 == 0:
            priorities[idx] += 10 / (1 + item)
    return priorities
